#!/usr/bin/env node
/**
 * Flatten css/main.imports.css @import chain into a single css/main.css.
 *
 * Why: browsers fetch @import stylesheets sequentially. On mobile that
 * waterfall routinely costs 2–4s before first paint. One bundled file = one RTT.
 *
 * Usage: node scripts/bundle-css.js
 */
const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');
const ENTRY = path.join(ROOT, 'css', 'main.imports.css');
const OUT = path.join(ROOT, 'css', 'main.css');

const IMPORT_RE = /@import\s+['"]([^'"]+)['"]\s*;/g;

function resolveImport(fromFile, spec) {
  // @import 'base/variables.css' is relative to the importing file's directory
  return path.normalize(path.join(path.dirname(fromFile), spec));
}

function bundle(file, seen = new Set()) {
  const abs = path.resolve(file);
  if (seen.has(abs)) return '';
  seen.add(abs);
  if (!fs.existsSync(abs)) {
    console.warn('[bundle-css] missing', abs);
    return `/* missing: ${path.relative(ROOT, abs)} */\n`;
  }
  let src = fs.readFileSync(abs, 'utf8');
  let out = '';
  let lastIndex = 0;
  let m;
  IMPORT_RE.lastIndex = 0;
  while ((m = IMPORT_RE.exec(src)) !== null) {
    out += src.slice(lastIndex, m.index);
    const child = resolveImport(abs, m[1]);
    out += `\n/* >>> ${path.relative(ROOT, child)} */\n`;
    out += bundle(child, seen);
    out += `\n/* <<< ${path.relative(ROOT, child)} */\n`;
    lastIndex = m.index + m[0].length;
  }
  out += src.slice(lastIndex);
  return out;
}

function minifyLight(css) {
  return css
    .replace(/\/\*[\s\S]*?\*\//g, '') // strip comments (including our markers)
    .replace(/\n{2,}/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n[ \t]+/g, '\n')
    .trim() + '\n';
}

const banner = `/* css/main.css — auto-generated by scripts/bundle-css.js
 * Source entry: css/main.imports.css (edit partials, then re-run bundle).
 * Do not hand-edit this file.
 */
`;

const bundled = bundle(ENTRY);
const final = banner + minifyLight(bundled);
fs.writeFileSync(OUT, final);
console.log(
  `[bundle-css] wrote ${path.relative(ROOT, OUT)} (${final.length} bytes from ${ENTRY})`
);
